-- movement_intelligence ladder slots
INSERT INTO coaching.phase_order_slot (key, name, description, phase_id, order_index, freshness_sensitivity, subrole_key)
SELECT v.key, v.name, v.description, sp.id, v.order_index, v.freshness_sensitivity, v.subrole_key
FROM coaching.session_phase sp
CROSS JOIN (VALUES
  ('ladder_linear_rhythm', 'Ladder Linear Rhythm', 'Linear ladder rhythm — One-In Ladder Run.', 301, 2, 'locomotion_sprint_mechanics'),
  ('ladder_sprint_mechanics', 'Ladder Sprint Mechanics', 'Sprint mechanics ladder — High-Knee A-March Ladder.', 302, 2, 'locomotion_sprint_mechanics'),
  ('ladder_lateral_rhythm', 'Ladder Lateral Rhythm', 'Lateral ladder rhythm — Lateral One-In Shuffle.', 303, 2, 'balance_coordination_rhythm'),
  ('ladder_crossover_coordination', 'Ladder Crossover Coordination', 'Crossover ladder — Lateral Crossover Step Ladder.', 304, 2, 'balance_coordination_rhythm'),
  ('ladder_fast_feet', 'Ladder Fast Feet', 'Fast-feet ladder — Ali Shuffle Ladder.', 305, 2, 'balance_coordination_rhythm'),
  ('ladder_transition_footwork', 'Ladder Transition Footwork', 'Turn and transition ladder — 90-Degree Ladder Turn Run.', 306, 2, 'balance_coordination_rhythm'),
  ('ladder_elastic_hops', 'Ladder Elastic Hops', 'Ladder hop family — Two-Foot Hop Each Box.', 307, 2, 'balance_coordination_rhythm'),
  ('ladder_reactive_decision', 'Ladder Reactive Decision', 'Reactive ladder decision — Coach Call-Out Ladder Pattern.', 308, 2, 'perception_action_reactive_movement'),
  ('ladder_reactive_partner', 'Ladder Reactive Partner', 'Partner reactive ladder — Partner Mirror Ladder.', 309, 2, 'perception_action_reactive_movement'),
  ('ladder_dual_task', 'Ladder Dual Task', 'Dual-task ladder — Ball Toss Ladder Feet.', 310, 2, 'perception_action_reactive_movement'),
  ('ladder_hand_foot_coordination', 'Ladder Hand Foot Coordination', 'Hand support ladder — Hand-Foot In-Out Bear Crawl Ladder.', 311, 2, 'balance_coordination_rhythm')
) AS v(key, name, description, order_index, freshness_sensitivity, subrole_key)
WHERE sp.key = 'movement_intelligence'
ON CONFLICT (key) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  phase_id = EXCLUDED.phase_id,
  order_index = EXCLUDED.order_index,
  freshness_sensitivity = EXCLUDED.freshness_sensitivity,
  subrole_key = EXCLUDED.subrole_key;

