INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility, participant_structure,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility', d.participant,
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('One-In Ladder Run', 'one-in-ladder-run', 'One-In Ladder Run is a ladder-focused exercise for clean single-contact foot rhythm, posture, and sprint-like front-side mechanics.', 'BEGINNER', 6, 2, 2, 15, 30, 55, 'individual', 'One-In Ladder Run uses the ladder to build clean single-contact foot rhythm, posture, and sprint-like front-side mechanics. Best used as a crisp, low-volume skill or power exposure rather than a fatigue circuit.', 'Primary phase: Movement Intelligence. Subrole: locomotion_sprint_mechanics. Treat the ladder as a constraint for precision; progress speed only after clean rhythm, posture, and spacing.', 'Fast feet are only good if they are clean feet.', 'Linear ladder rhythm', 'movement_intelligence', 'locomotion_sprint_mechanics', 'ladder_linear_rhythm', '{"primary_joint_actions":["ankle_dorsiflexion","hip_flexion_extension","knee_drive","trunk_upright_posture"],"primary_tissues":["plantar_foot","calves","hip_flexors","glutes"],"breathing_demand":"natural rhythmic breathing","balance_demand":"dynamic balance over changing foot positions","coordination_demand":"rapid foot placement, rhythm, and spatial awareness","impact_level":1}'::jsonb, '{"movement_description":"One-In Ladder Run uses the agility ladder as a visual target to train clean single-contact foot rhythm, posture, and sprint-like front-side mechanics. The athlete moves through the boxes with clean contacts, controlled posture, and enough rest to keep every rep crisp.","setup":["Lay the agility ladder flat and remove tripping hazards.","Show one slow walk-through rep before speed is allowed.","Start tall with eyes forward, arms ready, and feet just outside the first box."],"execution_steps":["Step through the ladder using the assigned foot pattern.","Keep contacts light, posture tall, and arms coordinated with the feet.","Finish the ladder cleanly, decelerate under control, and walk back for the next rep."],"coach_cues":["Eyes up.","Fast but clean.","Step, do not stomp.","Own the pattern before speed."],"athlete_cues":["Stay tall.","Light feet.","Hit every box clean.","Slow down if your feet get messy."],"breathing_cues":["Breathe naturally; do not hold breath to move faster."],"quality_gate":["No missed boxes for one full pass","Posture stays tall","Speed increases only after the pattern is clean"],"common_faults":["Looking down the entire time","Skipping boxes unintentionally","Heavy flat-foot contacts","Torso folding or twisting to chase speed"],"stop_signs":["Tripping on the ladder","Repeated missed contacts","Athlete cannot decelerate after the finish"]}'::jsonb),
  ('Two-In Quick Run', 'two-in-quick-run', 'Two-In Quick Run is a ladder-focused exercise for rapid alternating foot contacts while keeping hips tall and shoulders quiet.', 'BEGINNER', 6, 2, 2, 15, 30, 55, 'individual', 'Two-In Quick Run uses the ladder to build rapid alternating foot contacts while keeping hips tall and shoulders quiet. Best used as a crisp, low-volume skill or power exposure rather than a fatigue circuit.', 'Primary phase: Movement Intelligence. Subrole: locomotion_sprint_mechanics. Treat the ladder as a constraint for precision; progress speed only after clean rhythm, posture, and spacing.', 'Fast feet are only good if they are clean feet.', 'Linear ladder rhythm', 'movement_intelligence', 'locomotion_sprint_mechanics', 'ladder_linear_rhythm', '{"primary_joint_actions":["ankle_dorsiflexion","hip_flexion_extension","knee_drive","trunk_upright_posture"],"primary_tissues":["plantar_foot","calves","hip_flexors","glutes"],"breathing_demand":"natural rhythmic breathing","balance_demand":"dynamic balance over changing foot positions","coordination_demand":"rapid foot placement, rhythm, and spatial awareness","impact_level":1}'::jsonb, '{"movement_description":"Two-In Quick Run uses the agility ladder as a visual target to train rapid alternating foot contacts while keeping hips tall and shoulders quiet. The athlete moves through the boxes with clean contacts, controlled posture, and enough rest to keep every rep crisp.","setup":["Lay the agility ladder flat and remove tripping hazards.","Show one slow walk-through rep before speed is allowed.","Start tall with eyes forward, arms ready, and feet just outside the first box."],"execution_steps":["Step through the ladder using the assigned foot pattern.","Keep contacts light, posture tall, and arms coordinated with the feet.","Finish the ladder cleanly, decelerate under control, and walk back for the next rep."],"coach_cues":["Eyes up.","Fast but clean.","Step, do not stomp.","Own the pattern before speed."],"athlete_cues":["Stay tall.","Light feet.","Hit every box clean.","Slow down if your feet get messy."],"breathing_cues":["Breathe naturally; do not hold breath to move faster."],"quality_gate":["No missed boxes for one full pass","Posture stays tall","Speed increases only after the pattern is clean"],"common_faults":["Looking down the entire time","Skipping boxes unintentionally","Heavy flat-foot contacts","Torso folding or twisting to chase speed"],"stop_signs":["Tripping on the ladder","Repeated missed contacts","Athlete cannot decelerate after the finish"]}'::jsonb),
  ('High-Knee A-March Ladder', 'high-knee-a-march-ladder', 'High-Knee A-March Ladder is a ladder-focused exercise for march timing, knee lift, ankle dorsiflexion, and tall sprint posture.', 'BEGINNER', 6, 2, 2, 15, 30, 55, 'individual', 'High-Knee A-March Ladder uses the ladder to build march timing, knee lift, ankle dorsiflexion, and tall sprint posture. Best used as a crisp, low-volume skill or power exposure rather than a fatigue circuit.', 'Primary phase: Movement Intelligence. Subrole: locomotion_sprint_mechanics. Treat the ladder as a constraint for precision; progress speed only after clean rhythm, posture, and spacing.', 'Fast feet are only good if they are clean feet.', 'Sprint mechanics ladder', 'movement_intelligence', 'locomotion_sprint_mechanics', 'ladder_sprint_mechanics', '{"primary_joint_actions":["ankle_dorsiflexion","hip_flexion_extension","knee_drive","trunk_upright_posture"],"primary_tissues":["plantar_foot","calves","hip_flexors","glutes"],"breathing_demand":"natural rhythmic breathing","balance_demand":"dynamic balance over changing foot positions","coordination_demand":"rapid foot placement, rhythm, and spatial awareness","impact_level":0}'::jsonb, '{"movement_description":"High-Knee A-March Ladder uses the agility ladder as a visual target to train march timing, knee lift, ankle dorsiflexion, and tall sprint posture. The athlete moves through the boxes with clean contacts, controlled posture, and enough rest to keep every rep crisp.","setup":["Lay the agility ladder flat and remove tripping hazards.","Show one slow walk-through rep before speed is allowed.","Start tall with eyes forward, arms ready, and feet just outside the first box."],"execution_steps":["Step through the ladder using the assigned foot pattern.","Keep contacts light, posture tall, and arms coordinated with the feet.","Finish the ladder cleanly, decelerate under control, and walk back for the next rep."],"coach_cues":["Eyes up.","Fast but clean.","Step, do not stomp.","Own t