  ('Partner Tag Ladder Exit', 'partner-tag-ladder-exit', 'Partner Tag Ladder Exit is a ladder-focused exercise for perform clean ladder contacts then exit to chase or evade on a short cue.', 'ADVANCED', 10, 4, 2, 8, 75, 95, 'pairs', 'Partner Tag Ladder Exit uses the ladder to build perform clean ladder contacts then exit to chase or evade on a short cue. Best used as a crisp, low-volume skill or power exposure rather than a fatigue circuit.', 'Primary phase: Output. Subrole: reactive_agility_tumbling_output. Treat the ladder as a constraint for precision; progress speed only after clean rhythm, posture, and spacing.', 'Fast feet are only good if they are clean feet.', 'Partner reactive ladder', 'output', 'reactive_agility_tumbling_output', 'ladder_reactive_exit', '{"primary_joint_actions":["ankle_dorsiflexion","hip_flexion_extension","knee_drive","trunk_upright_posture"],"primary_tissues":["plantar_foot","calves","hip_flexors","glutes"],"breathing_demand":"natural rhythmic breathing","balance_demand":"dynamic balance over changing foot positions","coordination_demand":"rapid foot placement, rhythm, and spatial awareness","impact_level":2,"setup_metadata":{"ladder_layout":"flat ladder with 5-yard acceleration lane after final box","approach_speed":"controlled through ladder, aggressive on exit","rep_cap":"stop when exit speed drops or foot contacts become inaccurate"},"reactive_output_profile":{"stimulus_type":"coach, partner, color, number, or ball cue","decision_count":"1-3 options based on athlete level","amplitude_cap":"short ladder pass only; no fatigue chase"}}'::jsonb, '{"movement_description":"Partner Tag Ladder Exit uses the agility ladder as a visual target to train perform clean ladder contacts then exit to chase or evade on a short cue. The athlete moves through the boxes with clean contacts, controlled posture, and enough rest to keep every rep crisp.","setup":["Lay the agility ladder flat and remove tripping hazards.","Show one slow walk-through rep before speed is allowed.","Start tall with eyes forward, arms ready, and feet just outside the first box."],"execution_steps":["Step through the ladder using the assigned foot pattern.","Keep contacts light, posture tall, and arms coordinated with the feet.","Finish the ladder cleanly, decelerate under control, and walk back for the next rep."],"coach_cues":["Eyes up.","Fast but clean.","Step, do not stomp.","Own the pattern before speed."],"athlete_cues":["Stay tall.","Light feet.","Hit every box clean.","Slow down if your feet get messy."],"breathing_cues":["Breathe naturally; do not hold breath to move faster."],"quality_gate":["No missed boxes for one full pass","Posture stays tall","Speed increases only after the pattern is clean"],"common_faults":["Looking down the entire time","Skipping boxes unintentionally","Heavy flat-foot contacts","Torso folding or twisting to chase speed"],"stop_signs":["Tripping on the ladder","Repeated missed contacts","Athlete cannot decelerate after the finish"]}'::jsonb),
  ('Ball Toss Ladder Feet', 'ball-toss-ladder-feet', 'Ball Toss Ladder Feet is a ladder-focused exercise for maintain foot rhythm while catching or tossing a ball.', 'INTERMEDIATE', 9, 2, 2, 15, 30, 55, 'pairs', 'Ball Toss Ladder Feet uses the ladder to build maintain foot rhythm while catching or tossing a ball. Best used as a crisp, low-volume skill or power exposure rather than a fatigue circuit.', 'Primary phase: Movement Intelligence. Subrole: perception_action_reactive_movement. Treat the ladder as a constraint for precision; progress speed only after clean rhythm, posture, and spacing.', 'Fast feet are only good if they are clean feet.', 'Dual-task ladder', 'movement_intelligence', 'perception_action_reactive_movement', 'ladder_dual_task', '{"primary_joint_actions":["ankle_dorsiflexion","hip_flexion_extension","knee_drive","trunk_upright_posture"],"primary_tissues":["plantar_foot","calves","hip_flexors","glutes"],"breathing_demand":"natural rhythmic breathing","balance_demand":"dynamic balance over changing foot positions","coordination_demand":"rapid foot placement, rhythm, and spatial awareness","impact_level":1,"reactive_output_profile":{"stimulus_type":"coach, partner, color, number, or ball cue","decision_count":"1-3 options based on athlete level","amplitude_cap":"short ladder pass only; no fatigue chase"}}'::jsonb, '{"movement_description":"Ball Toss Ladder Feet uses the agility ladder as a visual target to train maintain foot rhythm while catching or tossing a ball. The athlete moves through the boxes with clean contacts, controlled posture, and enough rest to keep every rep crisp.","setup":["Lay the agility ladder flat and remove tripping hazards.","Show one slow walk-through rep before speed is allowed.","Start tall with eyes forward, arms ready, and feet just outside the first box."],"execution_steps":["Step through the ladder using the assigned foot pattern.","Keep contacts light, posture tall, and arms coordinated with the feet.","Finish the ladder cleanly, decelerate under control, and walk back for the next rep."],"coach_cues":["Eyes up.","Fast but clean.","Step, do not stomp.","Own the pattern before speed."],"athlete_cues":["Stay tall.","Light feet.","Hit every box clean.","Slow down if your feet get messy."],"breathing_cues":["Breathe naturally; do not hold breath to move faster."],"quality_gate":["No missed boxes for one full pass","Posture stays tall","Speed increases only after the pattern is clean"],"common_faults":["Looking down the entire time","Skipping boxes unintentionally","Heavy flat-foot contacts","Torso folding or twisting to chase speed"],"stop_signs":["Tripping on the ladder","Repeated missed contacts","Athlete cannot decelerate after the finish"]}'::jsonb),
  ('Dual-Task Ladder with Catch', 'dual-task-ladder-with-catch', 'Dual-Task Ladder with Catch is a ladder-focused exercise for combine ladder rhythm with visual tracking and hand-eye coordination.', 'ADVANCED', 9, 2, 2, 15, 30, 55, 'pairs', 'Dual-Task Ladder with Catch uses the ladder to build combine ladder rhythm with visual tracking and hand-eye coordination. Best used as a crisp, low-volume skill or power exposure rather than a fatigue circuit.', 'Primary phase: Movement Intelligence. Subrole: perception_action_reactive_movement. Treat the ladder as a constraint for precision; progress speed only after clean rhythm, posture, and spacing.', 'Fast feet are only good if they are clean feet.', 'Dual-task ladder', 'movement_intelligence', 'perception_action_reactive_movement', 'ladder_dual_task', '{"primary_joint_actions":["ankle_dorsiflexion","hip_flexion_extension","knee_drive","trunk_upright_posture"],"primary_tissues":["plantar_foot","calves","hip_flexors","glutes"],"breathing_demand":"natural rhythmic breathing","balance_demand":"dynamic balance over changing foot positions","coordination_demand":"rapid foot placement, rhythm, and spatial awareness","impact_level":1,"reactive_output_profile":{"stimulus_type":"coach, partner, color, number, or ball cue","decision_count":"1-3 options based on athlete level","amplitude_cap":"short ladder pass only; no fatigue chase"}}'::jsonb, '{"movement_description":"Dual-Task Ladder with Catch uses the agility ladder as a visual target to train combine ladder rhythm with visual tracking and hand-eye coordination. The athlete moves through the boxes with clean contacts, controlled posture, and enough rest to keep every rep crisp.","setup":["Lay the agility ladder flat and remove tripping hazards.","Show one slow walk-through rep before speed is allowed.","Start tall with eyes forward, arms ready, and feet just outside the first box."],"execution_steps":["Step through the ladder using the assigned foot pattern.","Keep contacts light, posture tall, and arms coordinated with the feet.","Finish the ladder cleanly, decelerate under control, and walk back for the next rep."],"coach_cues":["Eyes up.","Fast but clean.","Step, do not stomp.","Own the pattern before speed."],"athlete_cues":["Stay tall.","Light feet.","Hit every box clean.","Slow down if your feet get messy."],"breathing_cues":["Breathe naturally; do not hold breath to move faster."],"quality_gate":["No missed boxes for one full pass","Posture stays tall","Speed increases only after the pattern is clean"],"common_faults":["Looking down the entire time","Skipping boxes unintentionally","Heavy flat-foot contacts","Torso folding or twisting to chase speed"],"stop_signs":["Tripping on the ladder","Repeated missed contacts","Athlete cannot decelerate after the finish"]}'::jsonb),
  ('Bear Crawl Ladder', 'bear-crawl-ladder', 'Bear Crawl Ladder is a ladder-focused exercise for contralateral crawling rhythm, wrist/shoulder resilience, and trunk control.', 'BEGINNER', 7, 2, 1, 20, 45, 70, 'individual', 'Bear Crawl Ladder uses the ladder to build contralateral crawling rhythm, wrist/shoulder resilience, and trunk control. Best used as a crisp, low-volume skill or power exposure rather than a fatigue circuit.', 'Primary phase: Resilience. Subrole: scapular_wrist_hand_support_resilience. Treat the ladder as a constraint for precision; progress speed only after clean rhythm, posture, and spacing.', 'Fast feet are only good if they are clean feet.', 'Hand support ladder', 'resilience', 'scapular_wrist_hand_support_resilience', 'ladder_hand_support', '{"primary_joint_actions":["shoulder_flexion","scapular_protraction","wrist_extension","trunk_anti_rotation"],"primary_tissues":["shoulder_complex","wrist_flexors_extensors","anterior_core"],"breathing_demand":"controlled nasal breathing under trunk tension","balance_demand":"quadruped or plank base with hand-foot coordination","coordination_demand":"contralateral sequencing and trunk stiffness","impact_level":0}'::jsonb, '{"movement_description":"Bear Crawl Ladder uses the agility ladder as a visual target to train contralateral crawling rhythm, wrist/shoulder resilience, and trunk control. The athlete moves through the boxes with clean contacts, controlled posture, and enough rest to keep every rep crisp.","setup":["Place the agility ladder flat and clear space around it.","Start in a strong bear crawl or plank position with hands near the first box.","Brace the trunk before moving; spread fingers and press the floor away."],"execution_steps":["Move hands, or hands and feet, through each ladder box using the assigned pattern.","Keep hips quiet and shoulders stacked over strong hands.","Finish the ladder, reset posture, and walk back before the next rep."],"coach_cues":["Push the floor away.","Quiet hips.","Small clean hand steps.","Move like a table, not a snake."],"athlete_cues":["Strong hands.","Quiet hips.","Small steps.","Freeze if your belly drops."],"breathing_cues":["Breathe behind the brace; do not hold breath through the whole ladder."],"quality_gate":["No low-back sag","Hands hit boxes cleanly","Athlete can stop instantly without collapsing"],"common_faults":["Hips rocking side to side","Sagging low back","Hands landing outside the target boxes","Rushing until shoulder position collapses"],"stop_signs":["Wrist pain","Shoulder pinching","Loss of plank/bear position for more than one step"]}'::jsonb),
  ('Lateral Bear Crawl Ladder', 'lateral-bear-crawl-ladder', 'Lateral Bear Crawl Ladder is a ladder-focused exercise for sideways crawl coordination and shoulder/trunk control under a ladder constraint.', 'INTERMEDIATE', 8, 2, 1, 20, 45, 70, 'individual', 'Lateral Bear Crawl Ladder uses the ladder to build sideways crawl coordination and shoulder/trunk control under a ladder constraint. Best used as a crisp, low-volume skill or power exposure rather than a fatigue circuit.', 'Primary phase: Resilience. Subrole: scapular_wrist_hand_support_resilience. Treat the ladder as a constraint for precision; progress speed only after clean rhythm, posture, and spacing.', 'Fast feet are only good if they are clean feet.', 'Hand support ladder', 'resilience', 'scapular_wrist_hand_support_resilience', 'ladder_hand_support', '{"primary_joint_actions":["shoulder_flexion","scapular_protraction","wrist_extension","trunk_anti_rotation"],"primary_tissues":["shoulder_complex","wrist_flexors_extensors","anterior_core"],"breathing_demand":"controlled nasal breathing under trunk tension","balance_demand":"quadruped or plank base with hand-foot coordination","coordination_demand":"contralateral sequencing and trunk stiffness","impact_level":0}'::jsonb, '{"movement_description":"Lateral Bear Crawl Ladder uses the agility ladder as a visual target to train sideways crawl coordination and shoulder/trunk control under a ladder constraint. The athlete moves through the boxes with clean contacts, controlled posture, and enough rest to keep every rep crisp.","setup":["Place the agility ladder flat and clear space around it.","Start in a strong bear crawl or plank position with hands near the first box.","Brace the trunk before moving; spread fingers and press the floor away."],"execution_steps":["Move hands, or hands and feet, through each ladder box using the assigned pattern.","Keep hips quiet and shoulders stacked over strong hands.","Finish the ladder, reset posture, and walk back before the n